import{_ as r,c as t,o,aT as s}from"./chunks/framework.KoO-uqrk.js";const p=JSON.parse('{"title":"核心思想：解决“回调地狱”的利器","description":"","frontmatter":{},"headers":[],"relativePath":"front/interview/promiss.md","filePath":"front/interview/promiss.md"}'),i={name:"front/interview/promiss.md"};function n(l,e,a,m,d,g){return o(),t("div",null,e[0]||(e[0]=[s('<h1 id="核心思想-解决-回调地狱-的利器" tabindex="-1">核心思想：解决“回调地狱”的利器 <a class="header-anchor" href="#核心思想-解决-回调地狱-的利器" aria-label="Permalink to &quot;核心思想：解决“回调地狱”的利器&quot;">​</a></h1><ul><li><p>想象一下现实生活中的场景：</p><ul><li><em><strong>场景：</strong></em> 你要做饭，步骤是：1. 烧水 -&gt; 2. 煮面 -&gt; 3. 吃面。</li><li><em><strong>没有Promise（回调地狱）：</strong></em> 你开始烧水，然后必须死死盯着水壶，水一开，你立刻去煮面，然后再死死盯着锅，面一好，你立刻去吃。整个过程你什么也干不了，完全被“绑定”在了厨房。</li><li><em><strong>有Promise：</strong></em> 你开始烧水，然后跟水壶说：<em><strong>“水开了叫我”</strong></em>。然后你就可以去玩手机了。水壶（Promise）在水开后<em><strong>会通知你</strong></em>，你再去煮面，然后跟锅说：“<em><strong>面好了叫我</strong></em>”。你又可以去玩手机了。</li></ul></li><li><p><em><strong>Promise 就是一个“承诺”，它表示一个异步操作最终会完成（成功）或失败（拒绝），并在完成后给你一个结果。</strong></em></p></li></ul><h2 id="三种状态-就像等快递" tabindex="-1">三种状态：就像等快递 <a class="header-anchor" href="#三种状态-就像等快递" aria-label="Permalink to &quot;三种状态：就像等快递&quot;">​</a></h2><p>一个 Promise 对象有三种状态，<em><strong>一旦状态改变，就不可逆</strong></em>：</p><ul><li><code>pending</code><em><strong>(等待中)</strong></em> - <em><strong>比喻：</strong></em> 你的快递已经发货，正在路上。- <em><strong>初始状态，既没成功也没失败。</strong></em> 初始状态， neither fulfilled nor rejected.</li><li><code>fulfilled</code>（已成功）：操作成功完成。</li><li><code>rejected</code>（已拒绝）：操作失败。</li></ul>',5)]))}const _=r(i,[["render",n]]);export{p as __pageData,_ as default};
